+  transcription: TranscriptionConfig;
+  htmlText: string;
+  attemptedProviders: TranscriptSource[];
+  notes: string[];
+  effectiveVideoId: string | null;
+  durationMetadata: DurationMetadata;
+  canRunYtDlp: boolean;
+  pushHint: (hint: string) => void;
+};
